// TC Briefing -> Discord embed + button builder
// Supports legacy briefing[] action grouping and ROB-149 two-phase follow-up sends.

const botToken = ($env.DISCORD_TC_BRIEFING_BOT_TOKEN || '').trim();
const channelId = ($env.DISCORD_TC_BRIEFING_CHANNEL_ID || '').trim();
const paperclipBaseUrl = ($env.PAPERCLIP_UI_BASE_URL || '').trim().replace(/\/+$/, '');

if (!botToken || !channelId) {
  return [{
    json: {
      shouldSend: false,
      reason: !botToken
        ? 'DISCORD_TC_BRIEFING_BOT_TOKEN not configured'
        : 'DISCORD_TC_BRIEFING_CHANNEL_ID not configured',
    }
  }];
}

const input = $input.first().json;
const body = input.body || input;
const generatedAt = body.generated_at || new Date().toISOString();

function truncate(value, limit) {
  const text = String(value || '');
  return text.length > limit ? text.slice(0, limit - 1) + '…' : text;
}

function gateLine(name, gate) {
  if (!gate) return `${name}: tbd — TBD`;
  const status = gate.passed === false ? 'fail' : (gate.status || (gate.passed === true ? 'pass' : 'tbd'));
  const detail = gate.blocking_reason || gate.detail || '';
  return `${name}: ${status}${detail ? ' — ' + detail : ''}`;
}

function phaseContent(phase, source) {
  const baseText = source.text || source.brief_text || '자금 현황 재계산 대기';
  if (phase === 'tc_preliminary') {
    return truncate(baseText, 1900);
  }

  const gates = source.gate_results || {};
  const gateLines = ['G1', 'G2', 'G3', 'G4', 'G5', 'G6'].map(name => gateLine(name, gates[name]));
  const g2 = gates.G2 || {};
  const recommendation = g2.passed === false
    ? '🚫 신규 매수 차단 — G2 fail'
    : 'CIO 의견 대기 중 — gate 결과 확인 후 action 확정';
  const content = [
    baseText,
    '',
    '🎯 권고',
    recommendation,
    '',
    '📊 Gate 판정 결과',
    ...gateLines,
    '',
    '질문',
    '[funding] 경로 A·B 병행 가능 기준으로 board funding 금액/목적을 확정할 것.',
    '[action] 경로 A·B 병행 가능 조건에서 신규 매수, 현금 회복, 축소 중 하나를 선택할 것.',
  ].join('\n');
  return truncate(content, 1900);
}

function phaseEmbed(phase, source) {
  const title = phase === 'tc_preliminary'
    ? '📊 TC Preliminary — 자금 현황 재계산'
    : '🎯 CIO Pending Decision — Gate 판정 결과';
  return {
    title,
    description: phaseContent(phase, source),
    color: phase === 'tc_preliminary' ? 0x3498DB : 0xF1C40F,
    timestamp: generatedAt,
  };
}

function phaseItem(phase, source) {
  const embed = phaseEmbed(phase, source);
  const payload = { content: embed.description, embeds: [embed] };
  return {
    json: {
      shouldSend: true,
      phase,
      content: embed.description,
      payload,
    }
  };
}

const phaseMode = body.phase === 'tc_preliminary'
  || body.phase === 'cio_pending'
  || body.phase === 'tc_2phase'
  || body.followup === true
  || body.board_brief === true
  || body.tc_preliminary
  || body.cio_pending;

if (phaseMode) {
  const preliminarySource = body.tc_preliminary || body;
  const pendingSource = body.cio_pending || body;
  return [
    phaseItem('tc_preliminary', preliminarySource),
    phaseItem('cio_pending', pendingSource),
  ];
}

const briefing = Array.isArray(body.briefing) ? body.briefing : [];
const title = body.title || 'TC 브리핑';

if (briefing.length === 0) {
  return [{
    json: {
      shouldSend: false,
      reason: 'briefing array is empty',
    }
  }];
}

const categories = {
  sell:    { label: '매도', emoji: '🔴', color: 0xE74C3C },
  buy:     { label: '매수', emoji: '🟢', color: 0x2ECC71 },
  hold:    { label: '홀드', emoji: '🟡', color: 0xF1C40F },
  add_buy: { label: '추가매수', emoji: '🔵', color: 0x3498DB },
};

const grouped = {};
for (const item of briefing) {
  const action = String(item.action || 'hold').toLowerCase();
  if (!grouped[action]) grouped[action] = [];
  grouped[action].push(item);
}

const embeds = [];
const categoryOrder = ['sell', 'buy', 'add_buy', 'hold'];

for (const action of categoryOrder) {
  const items = grouped[action];
  if (!items || items.length === 0) continue;
  const cat = categories[action] || categories.hold;

  const fields = items.map(item => {
    const confidence = item.confidence != null ? ` (${item.confidence}%)` : '';
    const reasons = Array.isArray(item.reasons)
      ? item.reasons.slice(0, 3).join(' / ')
      : '';

    return {
      name: `${cat.emoji} ${item.symbol || 'Unknown'}${confidence}`,
      value: reasons || '근거 없음',
      inline: false,
    };
  });

  embeds.push({
    title: `${cat.emoji} ${cat.label} (${items.length}건)`,
    color: cat.color,
    fields: fields.slice(0, 25),
  });
}

const embedsToSend = embeds.slice(0, 10);

if (embedsToSend.length > 0) {
  embedsToSend[embedsToSend.length - 1].footer = {
    text: `${title} · ${new Date(generatedAt).toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' })}`,
  };
  embedsToSend[embedsToSend.length - 1].timestamp = generatedAt;
}

const buttons = [];
for (const action of categoryOrder) {
  const items = grouped[action];
  if (!items) continue;
  const cat = categories[action] || categories.hold;
  for (const item of items) {
    if (buttons.length < 25) {
      let buttonUrl = item.paperclip_issue_url || '';
      if (paperclipBaseUrl) {
        const identifier = item.paperclip_issue_identifier
          || (item.paperclip_issue_url || '').split('/').filter(Boolean).pop();
        if (identifier) {
          buttonUrl = `${paperclipBaseUrl}/ROB/issues/${identifier}`;
        }
      }
      if (buttonUrl) {
        buttons.push({
          type: 2,
          style: 5,
          label: `${cat.emoji} ${item.symbol || 'Unknown'} — Paperclip에서 결정하기`,
          url: buttonUrl,
        });
      }
    }
  }
}

const components = [];
for (let i = 0; i < buttons.length; i += 5) {
  components.push({
    type: 1,
    components: buttons.slice(i, i + 5),
  });
}
const componentsToSend = components.slice(0, 5);

const payload = { embeds: embedsToSend };
if (componentsToSend.length > 0) {
  payload.components = componentsToSend;
}

return [{
  json: {
    shouldSend: true,
    payload,
  }
}];
